// Parse WhatsApp Cloud API webhook structure
const body = $json.body || $json;
const change = body?.entry?.[0]?.changes?.[0]?.value;
const messages = change?.messages;

// Skip status updates, delivery receipts, etc. (no messages array)
if (!messages || messages.length === 0) {
  return [];
}

const msg = messages[0];
const chatId = String(msg.from);              // sender phone number e.g. "5491112345678"
const texto = msg.text?.body || msg.image?.caption || '';
const hasPhoto = msg.type === 'image';
const mediaId = hasPhoto ? msg.image?.id : null;
const phoneNumberId = change?.metadata?.phone_number_id; // business phone number ID

return [{ json: {
  texto,
  chatId,
  hasPhoto,
  mediaId,
  phoneNumberId,
  // Normalized .message for nodes that reference $json.chatId downstream
  message: {
    chat: { id: chatId },
    from: { id: chatId }
  }
}}];

const input = $json || {};
const step = input.step || "idle";
let expired = false;
if (input.updatedAt && step !== "idle") {
  const diffMin = (Date.now() - new Date(input.updatedAt).getTime()) / 60000;
  if (diffMin > 10) expired = true;
}
return [{ json: { ...input, step: expired ? "idle" : step, expired } }];

const upload = $input.first().json;
const fileData = $('Descargar media').first();   // binary comes from WhatsApp download
const comprobanteUrl = upload.webViewLink || upload.webContentLink ||
  `https://drive.google.com/file/d/${upload.id}/view`;
return [{ json: { comprobanteUrl, uploadedFileId: upload.id }, binary: fileData.binary }];

const expenseData = $('Normalizar extracción').first().json;
const obras = $input.all().map(i => i.json);

let menuLines = '';
for (const o of obras) {
  menuLines += `${o.Numero}E · ${o.Obra} — Egreso CCH\n`;
  menuLines += `${o.Numero}I · ${o.Obra} — Ingreso CCH\n`;
  menuLines += `${o.Numero}C · ${o.Obra} — Pago cliente\n`;
}

const unclearNote = expenseData.unclear
  ? '\n⚠️ Imagen poco clara. Igualmente indicá la obra para archivarla en revisión.\n'
  : '';

const mensaje = [
  '📋 Comprobante recibido:',
  `Proveedor: ${expenseData.proveedor || '(no detectado)'}`,
  `Monto: $${expenseData.ars || '?'}`,
  `Fecha: ${expenseData.fecha || '?'}`,
  `Concepto: ${expenseData.concepto || '?'}`,
  unclearNote,
  '¿A qué obra y tipo asignás este gasto?\n',
  menuLines.trim(),
  '\nRespondé con código (ej: 1E, 2I, 1C) o escribí cancelar.'
].join('\n');

return [{ json: { mensaje, obras, expenseData } }];

const text = ($('Preparar entrada').first().json.texto || '').trim();
const state = $json;
const obras = JSON.parse(state.obrasJson || '[]');

if (text.toLowerCase() === 'cancelar') {
  return [{ json: { valid: false, cancel: true, message: '' } }];
}

const match = text.match(/^(\d+)([EICeic])$/);
if (!match) {
  return [{ json: { valid: false, cancel: false,
    message: '⚠️ Código inválido. Usá número + letra, por ejemplo: 1E, 2I, 1C\n\nO escribí cancelar.' } }];
}

const obraNum = match[1];
const tipoCode = match[2].toUpperCase();
const tipoMap = { E: 'egreso', I: 'ingreso', C: 'doble' };
const selected = obras.find(o => String(o.Numero) === String(obraNum));

if (!selected) {
  return [{ json: { valid: false, cancel: false,
    message: `⚠️ Obra ${obraNum} no existe. Revisá el listado y respondé de nuevo.` } }];
}

return [{ json: {
  valid: true, cancel: false,
  operationType: tipoMap[tipoCode],
  selectedObra: selected.Obra,
  selectedSpreadsheetId: selected.SpreadsheetId,
  selectedSheetName: selected.SheetName,
  selectedInteresado: selected.Interesado || '',
  folderFacturasId: selected.FolderFacturasId || '',
  folderRevisionId: selected.FolderRevisionId || ''
}}];

const state = $('Consultar estado usuario').first().json;
const assignment = $('Validar asignación').first().json;
const pendingData = JSON.parse(state.pendingExpenseJson || '{}');
const operationType = assignment.operationType;
const interesado = assignment.selectedInteresado || '';

let tipo, caja;
if (operationType === 'ingreso') { tipo = 'Ingreso'; caja = 'CCH'; }
else if (operationType === 'doble') { tipo = 'Doble'; caja = interesado; }
else { tipo = 'Egreso'; caja = 'CCH'; }

return [{ json: {
  tipo, caja,
  id: '', or: '',
  tarea: pendingData.tarea || '',
  concepto: pendingData.concepto || '',
  proveedor: pendingData.proveedor || '',
  reciboNro: pendingData.reciboNro || '',
  fecha: pendingData.fecha || '',
  ars: Number(pendingData.ars || 0),
  comprobanteUrl: pendingData.comprobanteUrl || '',
  unclear: pendingData.unclear === true,
  operationType,
  selectedObra: assignment.selectedObra,
  selectedSpreadsheetId: assignment.selectedSpreadsheetId,
  selectedSheetName: assignment.selectedSheetName,
  folderFacturasId: assignment.folderFacturasId,
  folderRevisionId: assignment.folderRevisionId,
  selectedInteresado: interesado,
  uploadedFileId: state.uploadedFileId || ''
}}];

const gasto = $('Aplicar asignación').item.json;
const operationType = gasto.operationType || 'egreso';
const interesado = gasto.selectedInteresado || '';
const ars = Math.abs(Number(gasto.ars || 0));

if (operationType === 'doble') {
  return [
    { json: { ...gasto, tipo: 'Ingreso', ars: ars, caja: interesado } },
    { json: { ...gasto, tipo: 'Egreso', ars: -ars, caja: interesado } }
  ];
} else if (operationType === 'ingreso') {
  return [{ json: { ...gasto, tipo: 'Ingreso', ars: ars } }];
} else {
  return [{ json: { ...gasto, tipo: 'Egreso', ars: -ars } }];
}

