// Convierte la imagen a base64 para enviar a Gemini API
const item = $input.first();
const binary = item.binary?.data;
if (!binary) throw new Error('No se encontró imagen para procesar');

const buffer = await this.helpers.getBinaryDataBuffer(item, 'data');
const base64 = buffer.toString('base64');
const mimeType = binary.mimeType || 'image/jpeg';

const prompt = `Analizá esta imagen de factura o comprobante de pago argentino.
Extraé los datos y respondé ÚNICAMENTE con un JSON válido con esta estructura exacta, sin bloques de código ni texto adicional:
{
  "proveedor": "nombre del emisor o proveedor",
  "ars": número_total_sin_símbolo_de_moneda,
  "fecha": "DD/MM/YYYY",
  "concepto": "descripción breve del producto o servicio",
  "unclear": false
}
Reglas:
- ars debe ser un número JS (sin $, sin puntos de miles, usa punto decimal si aplica)
- Si algún campo no se puede leer claramente, poné null y unclear: true
- Si la imagen NO es una factura/comprobante, respondé exactamente: {"error":"no_invoice"}
Solo el JSON, sin texto adicional.`;

const requestBody = {
  contents: [{
    parts: [
      { inline_data: { mime_type: mimeType, data: base64 } },
      { text: prompt }
    ]
  }],
  generationConfig: {
    temperature: 0.1,
    maxOutputTokens: 512
  }
};

return [{ json: { requestBody } }];

// Parsea la respuesta de Gemini y devuelve la misma estructura que el antiguo "Normalizar extracción"
const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '';

// Limpiar posibles bloques de código Markdown
const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let data;
try {
  data = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Gemini no devolvió JSON válido. Respuesta: ' + text.substring(0, 300));
}

const comprobanteUrl = $('Preparar contexto obra').first().json.comprobanteUrl || '';
const uploadedFileId = $('Preparar contexto obra').first().json.uploadedFileId || '';

if (data.error) {
  return [{ json: {
    tarea: '', concepto: 'No identificado', proveedor: 'No identificado',
    reciboNro: '', fecha: '', ars: 0,
    comprobanteUrl, uploadedFileId,
    unclear: true
  }}];
}

return [{ json: {
  tarea: data.tarea || '',
  concepto: data.concepto || '',
  proveedor: data.proveedor || '',
  reciboNro: data.reciboNro || data.id || '',
  fecha: data.fecha || '',
  ars: Number(data.ars || 0),
  comprobanteUrl,
  uploadedFileId,
  unclear: data.unclear === true
}}];
